---
interface AccordionItem {
  title: string;
  content: string;
}

interface Props {
  items: AccordionItem[];
}

const { items } = Astro.props;
---

<div class="accordion">
  {items.map((item) => (
    <details class="accordion__item">
      <summary class="accordion__summary">
        <span class="accordion__title">{item.title}</span>
        <svg class="accordion__chevron" width="20" height="20" viewBox="0 0 20 20" fill="none" aria-hidden="true">
          <path d="M6 8l4 4 4-4" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/>
        </svg>
      </summary>
      <div class="accordion__content">
        <p>{item.content}</p>
      </div>
    </details>
  ))}
</div>

<style>
  .accordion {
    display: flex;
    flex-direction: column;
  }

  .accordion__item {
    border-bottom: 1px solid var(--color-stone);
  }

  .accordion__summary {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: var(--space-4);
    padding: var(--space-4) var(--space-2);
    cursor: pointer;
    list-style: none;
    transition: color var(--transition);
  }

  .accordion__summary::-webkit-details-marker {
    display: none;
  }

  .accordion__summary::marker {
    display: none;
    content: '';
  }

  .accordion__summary:hover {
    color: var(--color-terracotta);
  }

  .accordion__summary:focus-visible {
    outline: 2px solid var(--color-focus);
    outline-offset: 2px;
    border-radius: var(--radius-sm);
  }

  .accordion__title {
    font-family: var(--font-body);
    font-size: var(--text-lg);
    font-weight: 600;
    color: var(--color-ink);
  }

  .accordion__chevron {
    flex-shrink: 0;
    color: var(--color-body);
    transition: transform var(--transition);
  }

  details[open] > .accordion__summary .accordion__chevron {
    transform: rotate(180deg);
  }

  .accordion__content {
    padding: 0 var(--space-2) var(--space-4);
  }

  .accordion__content p {
    font-family: var(--font-body);
    font-size: var(--text-base);
    line-height: var(--leading-relaxed);
    color: var(--color-body);
    max-width: 48rem;
  }
</style>

---
/* ContactForm — styled HTML form with validation attributes.
   No action attribute — form submission handling is S05's job. */
---

<form class="contact-form" novalidate>
  <div class="contact-form__field">
    <label class="contact-form__label" for="contact-name">Name</label>
    <input
      class="contact-form__input"
      type="text"
      id="contact-name"
      name="name"
      required
      minlength="2"
      autocomplete="name"
      placeholder="Your name"
    />
  </div>

  <div class="contact-form__field">
    <label class="contact-form__label" for="contact-email">Email</label>
    <input
      class="contact-form__input"
      type="email"
      id="contact-email"
      name="email"
      required
      autocomplete="email"
      placeholder="you@example.com"
    />
  </div>

  <div class="contact-form__field">
    <label class="contact-form__label" for="contact-message">Message</label>
    <textarea
      class="contact-form__input contact-form__textarea"
      id="contact-message"
      name="message"
      required
      minlength="10"
      rows="5"
      placeholder="How can we help?"
    ></textarea>
  </div>

  <button class="contact-form__submit" type="submit">Send Message</button>
</form>

<style>
  .contact-form {
    display: flex;
    flex-direction: column;
    gap: var(--space-6);
    max-width: 36rem;
  }

  .contact-form__field {
    display: flex;
    flex-direction: column;
    gap: var(--space-2);
  }

  .contact-form__label {
    font-family: var(--font-body);
    font-size: var(--text-sm);
    font-weight: 600;
    color: var(--color-ink);
  }

  .contact-form__input {
    font-family: var(--font-body);
    font-size: var(--text-base);
    color: var(--color-body);
    background-color: var(--color-bg);
    border: 1px solid var(--color-stone);
    border-radius: var(--radius-sm);
    padding: var(--space-3) var(--space-4);
    transition: border-color var(--transition), box-shadow var(--transition);
  }

  .contact-form__input::placeholder {
    color: var(--color-stone);
  }

  .contact-form__input:focus {
    outline: none;
    border-color: var(--color-focus);
    box-shadow: 0 0 0 3px color-mix(in srgb, var(--color-focus) 25%, transparent);
  }

  .contact-form__textarea {
    resize: vertical;
    min-height: 8rem;
  }

  .contact-form__submit {
    align-self: flex-start;
    font-family: var(--font-body);
    font-size: var(--text-base);
    font-weight: 600;
    color: var(--color-bg);
    background-color: var(--color-terracotta);
    border: none;
    border-radius: var(--radius-sm);
    padding: var(--space-3) var(--space-8);
    cursor: pointer;
    transition: background-color var(--transition), box-shadow var(--transition);
  }

  .contact-form__submit:hover {
    background-color: color-mix(in srgb, var(--color-terracotta) 85%, black);
  }

  .contact-form__submit:focus-visible {
    outline: 2px solid var(--color-focus);
    outline-offset: 2px;
  }
</style>

---
interface Props {
  src: string;
  title: string;
  speaker?: string;
}

const { src, title, speaker } = Astro.props;
---

<div class="audio-player">
  <div class="audio-player__meta">
    <h3 class="audio-player__title">{title}</h3>
    {speaker && <p class="audio-player__speaker">{speaker}</p>}
  </div>
  <audio class="audio-player__audio" controls preload="metadata">
    {src && <source src={src} />}
    Your browser does not support the audio element.
  </audio>
</div>

<style>
  .audio-player {
    display: flex;
    flex-direction: column;
    gap: var(--space-3);
    border: 1px solid var(--color-stone);
    border-radius: var(--radius-md);
    padding: var(--space-4) var(--space-6);
    background-color: var(--color-bg);
  }

  .audio-player__meta {
    display: flex;
    flex-direction: column;
    gap: var(--space-1);
  }

  .audio-player__title {
    font-family: var(--font-heading);
    font-size: var(--text-lg);
    line-height: var(--leading-tight);
    color: var(--color-ink);
  }

  .audio-player__speaker {
    font-family: var(--font-body);
    font-size: var(--text-sm);
    color: var(--color-body);
  }

  .audio-player__audio {
    width: 100%;
  }
</style>

